  "data": {
    "attributes": {
      "name": "Updating the name",
      "description": "This is how to modify a collection via API.",
      "top_icon_md5": [
        "1bc1faf71106e964e44cb17ab4dd8d11"
      ],
      "tags": [],
      "ip_addresses_count": 1,
      "domains_count": 2,
      "creation_date": 1614784765,
      "last_modification_date": 1614784765,
      "references_count": 0,
      "alt_names": [],
      "urls_count": 2,
